98	// ---- Reserved word lookup ----
99	// Returns reserved word ID if the lowercase word starting at pos matches,
100	// or -1 if not a reserved word. Sets *end to position past the word.
101	int lookup_reserved(char *src, int pos, int *end) {
102	    int len;
103	
104	    len = str_match(src, pos, "rho");
105	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_RHO; }
