152	// ---- Tokenizer ----
153	// Tokenize input line into tok_type/tok_val/tok_pos arrays.
154	// Returns number of tokens (also stored in tok_count).
155	// On error, returns -1 (unrecognized character).
156	int tokenize(char *line) {
157	    int i = 0;
158	    int t = 0;
159	
160	    while (line[i] && t < TOK_MAX - 1) {
161	        // Skip whitespace
162	        if (line[i] == 32) {
163	            i++;
164	            continue;
165	        }
166	
167	        // Comment: # skips to end of line
168	        if (line[i] == 35) {
169	            break;
170	        }
171	
172	        // Number: digits, or underscore followed by digit (APL negative)
173	        if (is_digit(line[i]) || (line[i] == 95 && is_digit(line[i + 1]))) {
174	            tok_type[t] = TOK_NUM;
175	            tok_pos[t] = i;
176	            int end;
177	            tok_val[t] = parse_int(line, i, &end);
178	            i = end;
179	            t++;
180	            continue;
181	        }
182	
183	        // Lowercase letter: quad variables, reserved word, or unknown
184	        if (is_lower(line[i])) {
185	            // Check for quad variables first
186	            int len;
187	            len = str_match(line, i, "qled");
188	            if (len == 4 && !is_alnum(line[i + 4])) {
189	                tok_type[t] = TOK_QLED;
190	                tok_pos[t] = i;
191	                tok_val[t] = 0;
192	                t++;
193	                i = i + 4;
194	                continue;
195	            }
196	
197	            len = str_match(line, i, "qsw");
198	            if (len == 3 && !is_alnum(line[i + 3])) {
199	                tok_type[t] = TOK_QSW;
200	                tok_pos[t] = i;
201	                tok_val[t] = 0;
202	                t++;
203	                i = i + 3;
204	                continue;
205	            }
206	
207	            len = str_match(line, i, "qsvo");
208	            if (len == 4 && !is_alnum(line[i + 4])) {
209	                tok_type[t] = TOK_QSVO;
210	                tok_pos[t] = i;
211	                tok_val[t] = 0;
212	                t++;
213	                i = i + 4;
214	                continue;
215	            }
216	
217	            len = str_match(line, i, "qrl");
218	            if (len == 3 && !is_alnum(line[i + 3])) {
219	                tok_type[t] = TOK_QRL;
220	                tok_pos[t] = i;
221	                tok_val[t] = 0;
222	                t++;
223	                i = i + 3;
224	                continue;
225	            }
226	
227	            len = str_match(line, i, "qout");
228	            if (len == 4 && !is_alnum(line[i + 4])) {
229	                tok_type[t] = TOK_QOUT;
230	                tok_pos[t] = i;
231	                tok_val[t] = 0;
232	                t++;
233	                i = i + 4;
234	                continue;
235	            }
236	
237	            len = str_match(line, i, "qdl");
238	            if (len == 3 && !is_alnum(line[i + 3])) {
239	                tok_type[t] = TOK_QDL;
240	                tok_pos[t] = i;
241	                tok_val[t] = 0;
242	                t++;
243	                i = i + 3;
244	                continue;
245	            }
246	
247	            len = str_match(line, i, "goto");
248	            if (len == 4 && !is_alnum(line[i + 4])) {
249	                tok_type[t] = TOK_GOTO;
250	                tok_pos[t] = i;
251	                tok_val[t] = 0;
252	                t++;
253	                i = i + 4;
254	                continue;
255	            }
256	
257	            int end;
258	            int res = lookup_reserved(line, i, &end);
259	            if (res >= 0) {
260	                tok_type[t] = TOK_RES;
261	                tok_val[t] = res;
262	                tok_pos[t] = i;
263	                i = end;
264	                t++;
265	                continue;
266	            }
267	            // Unknown lowercase word -- error
268	            return -1;
269	        }
270	
271	        // String literal: 'ABC' (single-quoted, for qsvo left argument)
272	        if (line[i] == 39) {
273	            // 39 = single quote
274	            i++;
275	            tok_type[t] = TOK_STRING;
276	            tok_pos[t] = i;  // position of first char
277	            tok_val[t] = i;  // store start of string content
278	            while (line[i] && line[i] != 39) i++;
279	            if (line[i] != 39) return -1;  // unterminated string
280	            i++;  // skip closing quote
281	            t++;
282	            continue;
283	        }
284	
285	        // Uppercase letter: user identifier
286	        if (is_upper(line[i])) {
287	            tok_type[t] = TOK_IDENT;
288	            tok_pos[t] = i;
289	            tok_val[t] = i;  // store start position for name extraction
290	            i++;
291	            while (is_alnum(line[i])) i++;
292	            t++;
293	            continue;
294	        }
295	
296	        // Operators and punctuation
297	        if (line[i] == 43) { tok_type[t] = TOK_PLUS;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
298	        if (line[i] == 45) { tok_type[t] = TOK_MINUS;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
299	        if (line[i] == 42) { tok_type[t] = TOK_STAR;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
300	        if (line[i] == 47) { tok_type[t] = TOK_SLASH;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
301	        if (line[i] == 40) { tok_type[t] = TOK_LPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
302	        if (line[i] == 41) { tok_type[t] = TOK_RPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
303	
304	        // Quad: [] (IBM 5100 ASCII convention for ⎕) or bracket indexing [expr]
305	        if (line[i] == 91) {
306	            if (line[i + 1] == 93) {
307	                // [] = quad
308	                tok_type[t] = TOK_QUAD;
309	                tok_pos[t] = i;
310	                tok_val[t] = 0;
311	                t++;
312	                i = i + 2;
313	            } else {
314	                // [ = bracket index open
315	                tok_type[t] = TOK_LBRAK;
316	                tok_pos[t] = i;
317	                tok_val[t] = 0;
318	                t++;
319	                i++;
320	            }
321	            continue;
322	        }
323	        if (line[i] == 93) {
324	            tok_type[t] = TOK_RBRAK;
325	            tok_pos[t] = i;
326	            tok_val[t] = 0;
327	            t++;
328	            i++;
329	            continue;
330	        }
331	
332	        // Assignment: <-
333	        if (line[i] == 60 && line[i + 1] == 45) {
334	            tok_type[t] = TOK_ASSIGN;
335	            tok_pos[t] = i;
336	            tok_val[t] = 0;
337	            t++;
338	            i = i + 2;
339	            continue;
340	        }
341	
342	        // Comparison operators: = != >= <= > <
343	        // 61 '='  33 '!'  62 '>'  60 '<'
344	        if (line[i] == 61) { tok_type[t] = TOK_EQ; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
345	        if (line[i] == 33 && line[i + 1] == 61) { tok_type[t] = TOK_NE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
346	        if (line[i] == 62 && line[i + 1] == 61) { tok_type[t] = TOK_GE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
347	        if (line[i] == 60 && line[i + 1] == 61) { tok_type[t] = TOK_LE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
348	        if (line[i] == 62) { tok_type[t] = TOK_GT; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
349	        if (line[i] == 60) { tok_type[t] = TOK_LT; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
350	
351	        // Unrecognized character
352	        return -1;
353	    }
354	
355	    // Append EOL sentinel
356	    tok_type[t] = TOK_EOL;
357	    tok_pos[t] = i;
358	    tok_val[t] = 0;
359	    t++;
360	    tok_count = t;
361	    return t;
362	}
363	
364	// ---- Debug: print token list ----
365	// Useful for testing the tokenizer in isolation.
366	void tok_dump(char *line) {
367	    int i = 0;
368	    while (i < tok_count) {
369	        int ty = tok_type[i];
370	        if (ty == TOK_EOL) {
371	            io_print("EOL");
372	        } else if (ty == TOK_NUM) {
373	            io_print("NUM:");
374	            print_int(tok_val[i]);
375	        } else if (ty == TOK_IDENT) {
376	            io_print("ID:");
377	            int p = tok_val[i];
378	            while (is_alnum(line[p])) {
379	                putchar(line[p]);
380	                p++;
381	            }
382	        } else if (ty == TOK_RES) {
383	            io_print("RES:");
384	            int r = tok_val[i];
385	            if (r == RES_RHO)  io_print("rho");
386	            if (r == RES_IOTA) io_print("iota");
387	            if (r == RES_TAKE) io_print("take");
388	            if (r == RES_DROP) io_print("drop");
389	            if (r == RES_REV)  io_print("rev");
390	            if (r == RES_CAT)  io_print("cat");
391	        } else if (ty == TOK_PLUS)   { putchar(43); }
392	          else if (ty == TOK_MINUS)  { putchar(45); }
393	          else if (ty == TOK_STAR)   { putchar(42); }
394	          else if (ty == TOK_SLASH)  { putchar(47); }
395	          else if (ty == TOK_LPAREN) { putchar(40); }
396	          else if (ty == TOK_RPAREN) { putchar(41); }
397	          else if (ty == TOK_ASSIGN) { io_print("<-"); }
398	
399	        if (tok_type[i + 1] != TOK_EOL || ty == TOK_EOL) {
400	            // nothing
401	        }
402	        if (i + 1 < tok_count) putchar(32);
403	        i++;
404	    }
405	    putchar(10);
406	}
