1	// COR24 APL Interpreter -- Parser
2	// Right-to-left recursive descent with vector literal stranding.
3	// APL: all operators equal precedence, right-associative.
4	// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
5	// 1 2 3      ->  3-element vector (adjacent numbers strand)
6	
7	#pragma once
8	
9	// AST node types
10	#define NODE_NUM    0   // integer literal (val = value)
11	#define NODE_BINOP  1   // binary op (val = operator tok type)
12	#define NODE_NEG    2   // monadic negate (right = operand)
13	#define NODE_IDENT  3   // variable reference (val = symbol index)
14	#define NODE_ASSIGN 4   // assignment (val = symbol index, right = expr)
15	#define NODE_VEC    5   // vector literal (val = heap array index)
16	#define NODE_MONAD  6   // monadic primitive (val = RES_xxx, right = operand)
17	#define NODE_DYAD   7   // dyadic primitive (val = RES_xxx, left/right = args)
18	#define NODE_REDUCE 8   // reduce operator (val = op tok type, right = operand)
19	#define NODE_QOUT   9   // quad output (right = expr to print)
20	#define NODE_QLED  10   // qled read (no children)
21	#define NODE_QLED_ASSIGN 11  // qled <- expr (right = expr)
22	#define NODE_QSW   12   // qsw read (no children, read-only)
23	#define NODE_QSVO  13   // shared variable offer (val = sym index, right = AP expr)
24	#define NODE_SVO_READ  14   // shared var indexed read (val = sym index, right = index expr)
25	#define NODE_SVO_WRITE 15  // shared var indexed write (val = sym index, left = index, right = value)
26	#define NODE_GOTO  16   // unconditional branch (right = target expr)
27	#define NODE_CGOTO 17   // conditional branch (left = cond, right = target)
28	#define NODE_FNCALL 18  // user function call (val = fn index, left = left arg/-1, right = right arg)
29	#define NODE_QRL   19   // qrl read (no children — returns PRNG seed)
30	#define NODE_QRL_ASSIGN 20  // qrl <- expr (right = expr — sets PRNG seed)
31	#define NODE_QDL   21   // qdl expr (right = delay ms expr)
32	
33	#define AST_MAX 64
34	
35	// AST storage (parallel arrays)
36	int node_type[AST_MAX];
37	int node_val[AST_MAX];
38	int node_left[AST_MAX];
39	int node_right[AST_MAX];
40	int node_count;
41	
42	// Parser state
43	int parse_pos;
44	int parse_err;
45	char *parse_line;   // source line for identifier lookup
46	
47	// Allocate a new AST node
48	int ast_new() {
49	    if (node_count >= AST_MAX) {
50	        parse_err = 1;
51	        return 0;
52	    }
53	    int n = node_count;
54	    node_count++;
55	    node_left[n] = -1;
56	    node_right[n] = -1;
57	    return n;
58	}
59	
60	int ast_num(int val) {
61	    int n = ast_new();
62	    node_type[n] = NODE_NUM;
63	    node_val[n] = val;
64	    return n;
65	}
66	
67	int ast_binop(int op, int left, int right) {
68	    int n = ast_new();
69	    node_type[n] = NODE_BINOP;
70	    node_val[n] = op;
71	    node_left[n] = left;
72	    node_right[n] = right;
73	    return n;
74	}
75	
76	int ast_neg(int operand) {
77	    int n = ast_new();
78	    node_type[n] = NODE_NEG;
79	    node_right[n] = operand;
80	    return n;
81	}
82	
83	int ast_ident(int sym_idx) {
84	    int n = ast_new();
85	    node_type[n] = NODE_IDENT;
86	    node_val[n] = sym_idx;
87	    return n;
88	}
89	
90	int ast_assign(int sym_idx, int expr) {
91	    int n = ast_new();
92	    node_type[n] = NODE_ASSIGN;
93	    node_val[n] = sym_idx;
94	    node_right[n] = expr;
95	    return n;
96	}
97	
98	int ast_vec(int heap_idx) {
99	    int n = ast_new();
100	    node_type[n] = NODE_VEC;
101	    node_val[n] = heap_idx;
102	    return n;
103	}
104	
105	int ast_monad(int res_id, int operand) {
106	    int n = ast_new();
107	    node_type[n] = NODE_MONAD;
108	    node_val[n] = res_id;
109	    node_right[n] = operand;
110	    return n;
111	}
112	
113	int ast_dyad(int res_id, int left, int right) {
114	    int n = ast_new();
115	    node_type[n] = NODE_DYAD;
116	    node_val[n] = res_id;
117	    node_left[n] = left;
118	    node_right[n] = right;
119	    return n;
120	}
121	
122	int ast_reduce(int op, int operand) {
123	    int n = ast_new();
124	    node_type[n] = NODE_REDUCE;
125	    node_val[n] = op;
126	    node_right[n] = operand;
127	    return n;
128	}
129	
130	// Check if a reserved word can be used dyadically
131	int is_dyadic_res(int res_id) {
132	    return res_id == RES_RHO || res_id == RES_TAKE || res_id == RES_DROP || res_id == RES_CAT || res_id == RES_AND || res_id == RES_OR || res_id == RES_CEIL || res_id == RES_FLOOR || res_id == RES_COMPRESS || res_id == RES_PICK;
133	}
134	
135	// Temporary buffer for collecting strand elements
136	int strand_buf[64];
137	
138	int is_binop(int ty) {
139	    return ty == TOK_PLUS || ty == TOK_MINUS || ty == TOK_STAR || ty == TOK_SLASH ||
140	           ty == TOK_EQ || ty == TOK_NE || ty == TOK_LT || ty == TOK_GT ||
141	           ty == TOK_LE || ty == TOK_GE;
142	}
143	
144	// Check if token at pos could start an expression (for function call detection)
145	int can_start_expr(int pos) {
146	    int ty = tok_type[pos];
147	    if (ty == TOK_NUM || ty == TOK_LPAREN || ty == TOK_IDENT ||
148	        ty == TOK_MINUS || ty == TOK_RES || ty == TOK_QLED || ty == TOK_QSW ||
149	        ty == TOK_QRL || ty == TOK_STRING) return 1;
150	    if (is_binop(ty) && tok_type[pos + 1] == TOK_SLASH) return 1;  // reduce
151	    return 0;
152	}
153	
154	// Combined parse function avoids mutual recursion.
155	// mode 0 = expression, mode 1 = value only
156	int parse_node(int mode);
157	
158	int parse_node(int mode) {
159	    if (parse_err) return 0;
160	
161	    int left;
162	    int ty = tok_type[parse_pos];
163	
164	    // -- Parse a value --
165	
166	    if (ty == TOK_NUM) {
167	        left = ast_num(tok_val[parse_pos]);
168	        parse_pos++;
169	
170	        // Stranding: adjacent numbers form a vector (e.g. 1 2 3)
171	        if (tok_type[parse_pos] == TOK_NUM) {
172	            strand_buf[0] = node_val[left];
173	            int count = 1;
174	            while (tok_type[parse_pos] == TOK_NUM && count < 64) {
175	                strand_buf[count] = tok_val[parse_pos];
176	                parse_pos++;
177	                count++;
178	            }
179	            int aidx = arr_vector(count);
180	            if (aidx < 0) { parse_err = 1; return 0; }
181	            int si = 0;
182	            while (si < count) {
183	                arr_set(aidx, si, strand_buf[si]);
184	                si++;
185	            }
186	            left = ast_vec(aidx);
187	        }
188	    } else if (ty == TOK_LPAREN) {
189	        parse_pos++;
190	        left = parse_node(0);
191	        if (parse_err) return 0;
192	        if (tok_type[parse_pos] != TOK_RPAREN) {
193	            parse_err = 1;
194	            return 0;
195	        }
196	        parse_pos++;
197	    } else if (ty == TOK_QLED) {
198	        int n = ast_new();
199	        node_type[n] = NODE_QLED;
200	        left = n;
201	        parse_pos++;
202	    } else if (ty == TOK_QSW) {
203	        int n = ast_new();
204	        node_type[n] = NODE_QSW;
205	        left = n;
206	        parse_pos++;
207	    } else if (ty == TOK_QRL) {
208	        int n = ast_new();
209	        node_type[n] = NODE_QRL;
210	        left = n;
211	        parse_pos++;
212	    } else if (ty == TOK_STRING) {
213	        if (tok_type[parse_pos + 1] == TOK_QSVO) {
214	            // String as identifier for qsvo coupling: 'NAME' qsvo AP
215	            int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
216	            if (sym_idx < 0) { parse_err = 1; return 0; }
217	            left = ast_ident(sym_idx);
218	            parse_pos++;
219	        } else {
220	            // Character vector literal: 'hello' -> char vector
221	            int start = tok_val[parse_pos];
222	            int end = start;
223	            while (parse_line[end] && parse_line[end] != 39) end++;
224	            int len = end - start;
225	            int aidx = arr_vector(len);
226	            if (aidx < 0) { parse_err = 1; return 0; }
227	            arr_set_type(aidx, ARR_CHAR);
228	            int ci = 0;
229	            while (ci < len) {
230	                arr_set(aidx, ci, parse_line[start + ci]);
231	                ci++;
232	            }
233	            parse_pos++;
234	
235	            // String stranding: adjacent strings form a boxed vector
236	            if (tok_type[parse_pos] == TOK_STRING) {
237	                strand_buf[0] = aidx;
238	                int count = 1;
239	                while (tok_type[parse_pos] == TOK_STRING && count < 64) {
240	                    int s2 = tok_val[parse_pos];
241	                    int e2 = s2;
242	                    while (parse_line[e2] && parse_line[e2] != 39) e2++;
243	                    int l2 = e2 - s2;
244	                    int a2 = arr_vector(l2);
245	                    if (a2 < 0) { parse_err = 1; return 0; }
246	                    arr_set_type(a2, ARR_CHAR);
247	                    int k = 0;
248	                    while (k < l2) {
249	                        arr_set(a2, k, parse_line[s2 + k]);
250	                        k++;
251	                    }
252	                    strand_buf[count] = a2;
253	                    parse_pos++;
254	                    count++;
255	                }
256	                // Create boxed vector holding heap indices
257	                int bidx = arr_vector(count);
258	                if (bidx < 0) { parse_err = 1; return 0; }
259	                arr_set_type(bidx, ARR_BOXED);
260	                int bi = 0;
261	                while (bi < count) {
262	                    arr_set(bidx, bi, strand_buf[bi]);
263	                    bi++;
264	                }
265	                left = ast_vec(bidx);
266	            } else {
267	                left = ast_vec(aidx);
268	            }
269	        }
270	    } else if (ty == TOK_IDENT) {
271	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
272	        if (sym_idx < 0) { parse_err = 1; return 0; }
273	        parse_pos++;
274	        // Check for monadic function call
275	        int fi = fn_lookup(sym_idx);
276	        if (fi >= 0 && fn_left_sym[fi] < 0 && can_start_expr(parse_pos)) {
277	            // Monadic user function call: FN expr
278	            int arg = parse_node(0);
279	            if (parse_err) return 0;
280	            int nd = ast_new();
281	            node_type[nd] = NODE_FNCALL;
282	            node_val[nd] = fi;
283	            node_right[nd] = arg;
284	            left = nd;
285	        } else if (tok_type[parse_pos] == TOK_LBRAK) {
286	            // IDENT[expr] -- shared variable indexed read
287	            parse_pos++;
288	            int idx_expr = parse_node(0);
289	            if (parse_err) return 0;
290	            if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return 0; }
291	            parse_pos++;
292	            int nd = ast_new();
293	            node_type[nd] = NODE_SVO_READ;
294	            node_val[nd] = sym_idx;
295	            node_right[nd] = idx_expr;
296	            left = nd;
297	        } else {
298	            left = ast_ident(sym_idx);
299	        }
300	    } else if (is_binop(ty) && tok_type[parse_pos + 1] == TOK_SLASH) {
301	        // Reduce operator: +/ -/ */ (op followed by slash)
302	        int op = ty;
303	        parse_pos = parse_pos + 2;
304	        int operand = parse_node(0);
305	        if (parse_err) return 0;
306	        left = ast_reduce(op, operand);
307	    } else if (ty == TOK_RES && (tok_val[parse_pos] == RES_CEIL || tok_val[parse_pos] == RES_FLOOR || tok_val[parse_pos] == RES_AND || tok_val[parse_pos] == RES_OR) && tok_type[parse_pos + 1] == TOK_SLASH) {
308	        // Reduce with ceil/ floor/ and/ or/
309	        int rv = tok_val[parse_pos];
310	        int op = (rv == RES_CEIL) ? TOK_CEIL : (rv == RES_FLOOR) ? TOK_FLOOR : (rv == RES_AND) ? TOK_AND_OP : TOK_OR_OP;
311	        parse_pos = parse_pos + 2;
312	        int operand = parse_node(0);
313	        if (parse_err) return 0;
314	        left = ast_reduce(op, operand);
315	    } else if (ty == TOK_RES) {
316	        // Monadic primitive function (e.g. iota expr)
317	        int res_id = tok_val[parse_pos];
318	        parse_pos++;
319	        int operand = parse_node(0);
320	        if (parse_err) return 0;
321	        left = ast_monad(res_id, operand);
322	    } else if (ty == TOK_MINUS) {
323	        // Monadic negate: applies to entire right expression (APL rule)
324	        parse_pos++;
325	        int operand = parse_node(0);
326	        if (parse_err) return 0;
327	        left = ast_neg(operand);
328	    } else {
329	        parse_err = 1;
330	        return 0;
331	    }
332	
333	    // -- If mode 0 (expr) and next is binop or dyadic reserved, parse right --
334	
335	    if (mode == 0 && is_binop(tok_type[parse_pos])) {
336	        int op = tok_type[parse_pos];
337	        parse_pos++;
338	        int right = parse_node(0);
339	        if (parse_err) return 0;
340	        return ast_binop(op, left, right);
341	    }
342	
343	    if (mode == 0 && tok_type[parse_pos] == TOK_RES && is_dyadic_res(tok_val[parse_pos])) {
344	        int res_id = tok_val[parse_pos];
345	        parse_pos++;
346	        int right = parse_node(0);
347	        if (parse_err) return 0;
348	        return ast_dyad(res_id, left, right);
349	    }
350	
351	    // Shared variable offer: 'NAME' qsvo EXPR  (or legacy: IDENT qsvo EXPR)
352	    if (mode == 0 && tok_type[parse_pos] == TOK_QSVO && node_type[left] == NODE_IDENT) {
353	        int sym_idx = node_val[left];
354	        parse_pos++;
355	        int right = parse_node(0);
356	        if (parse_err) return 0;
357	        int n = ast_new();
358	        node_type[n] = NODE_QSVO;
359	        node_val[n] = sym_idx;
360	        node_right[n] = right;
361	        return n;
362	    }
363	
364	    // Dyadic user function call: expr FN expr
365	    if (mode == 0 && tok_type[parse_pos] == TOK_IDENT) {
366	        int dsym = sym_lookup(parse_line, tok_val[parse_pos]);
367	        if (dsym >= 0) {
368	            int dfi = fn_lookup(dsym);
369	            if (dfi >= 0 && fn_left_sym[dfi] >= 0) {
370	                parse_pos++;
371	                int right = parse_node(0);
372	                if (parse_err) return 0;
373	                int nd = ast_new();
374	                node_type[nd] = NODE_FNCALL;
375	                node_val[nd] = dfi;
376	                node_left[nd] = left;
377	                node_right[nd] = right;
378	                return nd;
379	            }
380	        }
381	    }
382	
383	    return left;
384	}
385	
386	// Parse the token stream. Returns root node index, or -1 on error.
387	// line is needed for identifier name resolution into the symbol table.
388	int parse(char *line) {
389	    node_count = 0;
390	    parse_pos = 0;
391	    parse_err = 0;
392	    parse_line = line;
393	
394	    // Check for qled assignment: qled <- expr
395	    if (tok_type[0] == TOK_QLED && tok_type[1] == TOK_ASSIGN) {
396	        parse_pos = 2;
397	        int expr = parse_node(0);
398	        if (parse_err) return -1;
399	        if (tok_type[parse_pos] != TOK_EOL) return -1;
400	        int n = ast_new();
401	        node_type[n] = NODE_QLED_ASSIGN;
402	        node_right[n] = expr;
403	        return n;
404	    }
405	
406	    // Check for qsw assignment: qsw is read-only, reject with SYNTAX ERROR
407	    if (tok_type[0] == TOK_QSW && tok_type[1] == TOK_ASSIGN) {
408	        return -1;
409	    }
410	
411	    // Check for qrl assignment: qrl <- expr (set PRNG seed)
412	    if (tok_type[0] == TOK_QRL && tok_type[1] == TOK_ASSIGN) {
413	        parse_pos = 2;
414	        int expr = parse_node(0);
415	        if (parse_err) return -1;
416	        if (tok_type[parse_pos] != TOK_EOL) return -1;
417	        int n = ast_new();
418	        node_type[n] = NODE_QRL_ASSIGN;
419	        node_right[n] = expr;
420	        return n;
421	    }
422	
423	    // Check for quad output: [] <- expr or qout <- expr
424	    if ((tok_type[0] == TOK_QUAD || tok_type[0] == TOK_QOUT) && tok_type[1] == TOK_ASSIGN) {
425	        parse_pos = 2;
426	        int expr = parse_node(0);
427	        if (parse_err) return -1;
428	        if (tok_type[parse_pos] != TOK_EOL) return -1;
429	        int n = ast_new();
430	        node_type[n] = NODE_QOUT;
431	        node_right[n] = expr;
432	        return n;
433	    }
434	
435	    // Check for qdl (delay): qdl expr
436	    if (tok_type[0] == TOK_QDL) {
437	        parse_pos = 1;
438	        int expr = parse_node(0);
439	        if (parse_err) return -1;
440	        if (tok_type[parse_pos] != TOK_EOL) return -1;
441	        int n = ast_new();
442	        node_type[n] = NODE_QDL;
443	        node_right[n] = expr;
444	        return n;
445	    }
446	
447	    // Check for shared variable indexed write: IDENT[expr] <- expr
448	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_LBRAK) {
449	        int sym_idx = sym_lookup(line, tok_val[0]);
450	        if (sym_idx < 0) { return -1; }
451	        parse_pos = 2;
452	        int idx_expr = parse_node(0);
453	        if (parse_err) return -1;
454	        if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return -1; }
455	        parse_pos++;
456	        if (tok_type[parse_pos] == TOK_ASSIGN) {
457	            // IDENT[expr] <- expr (indexed write)
458	            parse_pos++;
459	            int val_expr = parse_node(0);
460	            if (parse_err) return -1;
461	            if (tok_type[parse_pos] != TOK_EOL) return -1;
462	            int n = ast_new();
463	            node_type[n] = NODE_SVO_WRITE;
464	            node_val[n] = sym_idx;
465	            node_left[n] = idx_expr;
466	            node_right[n] = val_expr;
467	            return n;
468	        }
469	        if (tok_type[parse_pos] != TOK_EOL) {
470	            // IDENT[expr] followed by more (could be in expression context)
471	            // For now, only standalone read supported at top level
472	            // Fall through to expression parsing below
473	            parse_pos = 0;
474	            node_count = 0;
475	            parse_err = 0;
476	        } else {
477	            // IDENT[expr] standalone read
478	            int n = ast_new();
479	            node_type[n] = NODE_SVO_READ;
480	            node_val[n] = sym_idx;
481	            node_right[n] = idx_expr;
482	            return n;
483	        }
484	    }
485	
486	    // Check for goto: goto expr  or  goto (expr)/LABEL
487	    if (tok_type[0] == TOK_GOTO) {
488	        parse_pos = 1;
489	        if (tok_type[1] == TOK_LPAREN) {
490	            // Conditional: goto (expr)/TARGET
491	            parse_pos = 2;
492	            int cond = parse_node(0);
493	            if (parse_err) return -1;
494	            if (tok_type[parse_pos] != TOK_RPAREN) return -1;
495	            parse_pos++;
496	            if (tok_type[parse_pos] != TOK_SLASH) return -1;
497	            parse_pos++;
498	            int target = parse_node(0);
499	            if (parse_err) return -1;
500	            if (tok_type[parse_pos] != TOK_EOL) return -1;
501	            int n = ast_new();
502	            node_type[n] = NODE_CGOTO;
503	            node_left[n] = cond;
504	            node_right[n] = target;
505	            return n;
506	        }
507	        // Unconditional: goto expr
508	        int target = parse_node(0);
509	        if (parse_err) return -1;
510	        if (tok_type[parse_pos] != TOK_EOL) return -1;
511	        int n = ast_new();
512	        node_type[n] = NODE_GOTO;
513	        node_right[n] = target;
514	        return n;
515	    }
516	
517	    // Check for assignment: IDENT <- expr
518	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_ASSIGN) {
519	        int sym_idx = sym_lookup(line, tok_val[0]);
520	        if (sym_idx < 0) { return -1; }
521	        parse_pos = 2;
522	        int expr = parse_node(0);
523	        if (parse_err) return -1;
524	        if (tok_type[parse_pos] != TOK_EOL) return -1;
525	        return ast_assign(sym_idx, expr);
526	    }
527	
528	    int root = parse_node(0);
529	
530	    if (!parse_err && tok_type[parse_pos] != TOK_EOL) {
531	        parse_err = 1;
532	    }
533	
534	    if (parse_err) return -1;
535	    return root;
536	}
537	
538	// Debug: dump AST with full parenthesization
539	void ast_dump(int n) {
540	    if (n < 0 || n >= node_count) return;
541	
542	    int ty = node_type[n];
543	    if (ty == NODE_NUM) {
544	        print_int(node_val[n]);
545	    } else if (ty == NODE_BINOP) {
546	        putchar(40);
547	        ast_dump(node_left[n]);
548	        putchar(32);
549	        if (node_val[n] == TOK_PLUS)  putchar(43);
550	        if (node_val[n] == TOK_MINUS) putchar(45);
551	        if (node_val[n] == TOK_STAR)  putchar(42);
552	        if (node_val[n] == TOK_SLASH) putchar(47);
553	        putchar(32);
554	        ast_dump(node_right[n]);
555	        putchar(41);
556	    } else if (ty == NODE_NEG) {
557	        putchar(40);
558	        putchar(45);
559	        ast_dump(node_right[n]);
560	        putchar(41);
561	    }
562	}
