// COR24 APL Interpreter -- Tokenizer
// Lexes input line into token array for the parser.

#pragma once

// Token types
#define TOK_EOL     0   // end of line
#define TOK_NUM     1   // integer literal (value in tok_val)
#define TOK_IDENT   2   // user identifier (uppercase, pos in tok_val)
#define TOK_PLUS    3   // +
#define TOK_MINUS   4   // - (parser decides monadic vs dyadic)
#define TOK_STAR    5   // *
#define TOK_SLASH   6   // /
#define TOK_LPAREN  7   // (
#define TOK_RPAREN  8   // )
#define TOK_ASSIGN  9   // <-
#define TOK_RES    10   // reserved word (ID in tok_val)
#define TOK_QUAD   11   // quad ([] — bare quad for I/O)
#define TOK_QLED   12   // qled — LED D2 hardware I/O
#define TOK_QSW    13   // qsw — switch S2 hardware I/O (read-only)
#define TOK_QSVO   14   // qsvo — shared variable offer (□SVO)
#define TOK_LBRAK  15   // [ (bracket index open)
#define TOK_RBRAK  16   // ] (bracket index close)
#define TOK_GOTO   17   // goto — branch (→)
#define TOK_STRING 18   // string literal 'ABC' (pos of first char in tok_val)
#define TOK_EQ     19   // =
#define TOK_NE     20   // !=
#define TOK_LT     21   // <
#define TOK_GT     22   // >
#define TOK_LE     23   // <=
#define TOK_GE     24   // >=
#define TOK_CEIL   25   // ceil (max) — internal only, used in reduce nodes
#define TOK_FLOOR  26   // floor (min) — internal only, used in reduce nodes
#define TOK_QRL    27   // qrl — random link seed (□RL)
#define TOK_QOUT   28   // qout — quad output (□ <- expr)
#define TOK_QDL    29   // qdl — delay N milliseconds (□DL)
#define TOK_AND_OP 30   // and — internal only, used in reduce nodes
#define TOK_OR_OP  31   // or — internal only, used in reduce nodes

// Reserved word IDs
#define RES_RHO     0
#define RES_IOTA    1
#define RES_TAKE    2
#define RES_DROP    3
#define RES_REV     4
#define RES_CAT     5
#define RES_AND     6
#define RES_OR      7
#define RES_NOT     8
#define RES_CEIL    9
#define RES_FLOOR  10
#define RES_COMPRESS 11
#define RES_PICK    12
#define RES_ROLL    13
#define RES_FMT     14

#define TOK_MAX    64   // max tokens per line

// Token storage (parallel arrays)
