        if (node_val[n] == TOK_SLASH) putchar(47);
        putchar(32);
        ast_dump(node_right[n]);
        putchar(41);
    } else if (ty == NODE_NEG) {
        putchar(40);
        putchar(45);
        ast_dump(node_right[n]);
        putchar(41);
    }
}

